---

每個物品只能選一次，即要麼選，要麼不選。

所以 0-1 背包是「選或不選」的代表。關於「列舉選哪個」的代表，見本題單的「4.2 最長遞增子序列」。

**核心特點**：
- 每個物品只有一件，選或不選
- 狀態轉移：`dp[j] = max(dp[j], dp[j - w] + v)`
- **必須倒序遍歷**容量 j，以確保每個物品只被選一次。

```cpp
// 0-1 背包（一維空間優化）
int knapsack01(vector<int>& w, vector<int>& v, int capacity) {
    int n = w.size();
    vector<int> dp(capacity + 1, 0);
    for (int i = 0; i < n; ++i) {
        for (int j = capacity; j >= w[i]; --j) {
            // 倒序確保每個物品只選一次
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
        }
    }
    return dp[capacity];
}
```

物品可以重複選，無個數限制。

**核心特點**：
- 每個物品有無數件，可以重複選
- 狀態轉移：`dp[j] = max(dp[j], dp[j - w] + v)`
- **必須正序遍歷**容量 j，以允許重複選擇同一個物品。

```cpp
// 完全背包（一維空間優化）
int knapsackComplete(vector<int>& w, vector<int>& v, int capacity) {
    int n = w.size();
    vector<int> dp(capacity + 1, 0);
    for (int i = 0; i < n; ++i) {
        for (int j = w[i]; j <= capacity; ++j) { // 正序允許重複選取
            dp[j] = max(dp[j], dp[j - w[i]] + v[i]);
        }
    }
    return dp[capacity];
}
```

物品可以重複選，有個數限制。

**求方案數**

注意求方案數的題目不能用二進位制優化。比如從 6 個相同物品中選 3 個，只有一種選法。但按照二進位制優化，會把 6 分解為 1+2+3，有 1+2 和 3 兩種選法。

如果要優化，可以考慮用 [同餘字首和](https://leetcode.cn/problems/count-of-sub-multisets-with-bounded-sum/solutions/2482876/duo-zhong-bei-bao-fang-an-shu-cong-po-su-f5ay/) 優化。

```cpp
// 多重背包（二進位制分組優化）
// 將數量 c 拆為 1, 2, 4, ..., 餘數，轉為 0-1 背包
vector<int> dp(capacity + 1, 0);
for (int i = 0; i < n; ++i) {
    int cnt = c[i], wi = w[i], vi = v[i];
    for (int k = 1; cnt > 0; k *= 2) {
        int take = min(k, cnt); // 二進位制分組：1, 2, 4, ...
        cnt -= take;
        for (int j = capacity; j >= take * wi; --j) {
            dp[j] = max(dp[j], dp[j - take * wi] + take * vi);
        }
    }
}
```

同一組內的物品至多/恰好選一個。

```cpp
// 分組背包
// groups[g] = {{w, v}, ...} 表示第 g 組的物品
vector<int> dp(capacity + 1, 0);
for (auto& group : groups) {
    for (int j = capacity; j >= 0; --j) { // 倒序遍歷容量
        for (auto& [wi, vi] : group) {
            if (j >= wi) {
                dp[j] = max(dp[j], dp[j - wi] + vi);
            }
        }
    }
}
```

也叫樹上背包、依賴背包等。

> 注：目前力扣只有無依賴的背包，時間複雜度為 $O(nW^2)$。如果有依賴，可以優化到 $O(nW)$。

```cpp
// 樹形背包（在樹上做 0-1 背包）
// dp[u][j] = 以 u 為根的子樹中，選 j 的容量的最大價值
void dfs(int u, int fa) {
    dp[u][0] = 0;
    for (int v : adj[u]) {
        if (v == fa) {
            continue;
        }
        dfs(v, u);
        // 倒序合併子節點 v 的背包
        for (int j = capacity; j >= 0; --j) {
            for (int k = 1; k <= j; ++k) {
                dp[u][j] = max(dp[u][j], dp[u][j - k] + dp[v][k]);
            }
        }
    }
}
```

講解：[最長公共子序列 編輯距離【基礎演算法精講 19】](https://www.bilibili.com/video/BV1TM4y1o7ug/)

一般定義 `f[i][j]` 表示對 `(s[:i], t[:j])` 的求解結果。

```cpp
// 最長遞增子序列（二分優化 O(n log n)）
vector<int> tails;
for (int x : nums) {
    auto it = lower_bound(tails.begin(), tails.end(), x);
    if (it == tails.end()) {
        tails.push_back(x);
    } else {
        *it = x;
    }
}
// tails.size() 即 LIS 長度
```

講解：[最長公共子序列 編輯距離【基礎算法精講 19】](https://www.bilibili.com/video/BV1TM4y1o7ug/)

一般定義 f[i][j] 表示對 (s[:i],t[:j]) 的求解結果。

---



**最長公共子序列（LCS）基礎**：
- `dp[i][j]` 表示 `s[0..i-1]` 和 `t[0..j-1]` 的 LCS 長度
- 若 `s[i-1] == t[j-1]`：`dp[i][j] = dp[i-1][j-1] + 1`
- 否則：`dp[i][j] = max(dp[i-1][j], dp[i][j-1])`

```cpp
// LCS 完整實作（含空間優化）
int longestCommonSubsequence(string& s, string& t) {
    int m = s.size(), n = t.size();
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
    for (int i = 1; i <= m; ++i) {
        for (int j = 1; j <= n; ++j) {
            if (s[i - 1] == t[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1] + 1; // 字元相同，LCS +1
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]); // 字元不同，取較優
            }
        }
    }
    return dp[m][n];
}
```

**LCS 核心模板**：
`dp[i][j]` 表示 `s1[0..i-1]` 與 `s2[0..j-1]` 的 LCS 長度。

```cpp
// LCS：dp[i][j] = s[0..i-1] 與 t[0..j-1] 的最長公共子序列長度
vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
for (int i = 1; i <= m; ++i) {
    for (int j = 1; j <= n; ++j) {
        if (s_1[i - 1] == s_2[j - 1]) {
            dp[i][j] = dp[i - 1][j - 1] + 1; // 字元相同，LCS 長度 +1
        } else {
            dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]); // 字元不同，取較優子問題
        }
    }
}
```

講解：[最長遞增子序列【基礎演算法精講 20】](https://www.bilibili.com/video/BV1ub411Q7sB/)

做法有很多：
1. 列舉選哪個。（見講解）
2. 二分。（見講解）
3. 計算 a 和把 a 排序後的陣列 sortedA 的最長公共子序列。（用 LCS 求 LIS）
4. 資料結構優化。（見 [2407 題](https://leetcode.cn/problems/longest-increasing-subsequence-ii/)）

**LIS 貪心 + 二分模板 ($O(n \log n)$)**：

```cpp
// 貪心 + 二分：g[i] 為長度 i+1 的遞增子序列末尾最小值
vector<int> g;
for (int x : nums) {
    auto it = lower_bound(g.begin(), g.end(), x); // 找第一個 >= x 的位置
    if (it == g.end()) {
        g.push_back(x); // x 比所有末尾都大，延長序列
    } else {
        *it = x; // 替換為更小的值，使後續更容易延長
    }
}

int ans = g.size();
```

