---



**最長遞增子序列（LIS）基礎**：
- $O(n²)$ 做法：`dp[i]` 表示以 `nums[i]` 結尾的 LIS 長度
- $O(n \log n)$ 做法：維護一個遞增陣列，二分查詢插入位置

```cpp
// O(n log n) Lis
int lengthOfLis(vector<int>& nums) {
    vector<int> tails;
    for (int x : nums) {
        auto it = lower_bound(tails.begin(), tails.end(), x);
        if (it == tails.end()) {
            tails.push_back(x); // x 比所有末尾都大，延長序列
        } else {
            *it = x; // 替換為更小的值，使後續更容易延長
        }
    }
    return tails.size();
}
```

**劃分型 DP：約束劃分個數**：
- 將陣列恰好劃分為 k 段，最小化/最大化目標值
- `dp[i][k]` 表示前 i 個元素劃分為 k 段的最優值
- 轉移：列舉最後一段的起點

```cpp
// dp[i][k] = min(dp[j][k-1] + cost(j+1, i)) for j < i
vector<vector<int>> dp(n + 1, vector<int>(k_limit + 1, INT_MAX));
dp[0][0] = 0; // 前 0 個元素分 0 段，代價為 0
for (int i = 1; i <= n; ++i) {
    for (int k = 1; k <= k_limit; ++k) {
        for (int j = k - 1; j < i; ++j) {
            if (dp[j][k - 1] != INT_MAX) {
                dp[i][k] = min(dp[i][k], dp[j][k - 1] + cost(j + 1, i));
            }
        }
    }
}
```

```cpp
// 劃分型 DP 模板
// dp[i] 表示前 i 個元素的最優劃分結果
vector<int> dp(n + 1, INT_MAX);
dp[0] = 0;
for (int i = 1; i <= n; i++)
    for (int j = 0; j < i; j++)
        if (valid(j, i)) // 檢查 a[j..i-1] 是否為合法的一段
            dp[i] = min(dp[i], dp[j] + cost(j, i));
```

**狀態機 DP**：將問題的狀態抽象為有限狀態機，每個位置在若干狀態之間轉移。一般定義 `dp[i][j]` 表示處理到第 i 個元素時，處於狀態 j 的最優值。

**核心思路**：
1. **畫出狀態轉移圖**：明確有哪些狀態、狀態之間如何轉移
2. **定義 DP 陣列**：`dp[i][j]` 表示第 i 步處於狀態 j 時的最優值
3. **根據轉移圖寫轉移方程**：每個狀態只能從它的前驅狀態轉移而來

**典型狀態設計**：

| 問題 | 狀態 | 說明 |
|------|------|------|
| 買賣股票 | 持有 / 未持有 | 買入=未持有→持有，賣出=持有→未持有 |
| 含冷凍期 | 持有 / 未持有(可買) / 冷凍期 | 賣出後進入冷凍期，冷凍期後才能買 |
| 粉刷房子 | 紅 / 藍 / 綠 | 相鄰房子不能同色 |
| 字串匹配 | 匹配到第 j 個字元 | KMP / 正規表示式匹配 |

**C++ 模板（買賣股票，最多 k 次交易）**：

```cpp
// prices: 每天的股價, k: 最多交易次數
// 狀態：dp[j][0] = 第 j 次交易，未持有股票的最大利潤
//       dp[j][1] = 第 j 次交易，持有股票的最大利潤
int maxProfit(int k, vector<int>& prices) {
    // dp[j][0]: 完成了 j 次交易，手上沒股票
    // dp[j][1]: 正在進行第 j 次交易，手上有股票
    vector<array<int, 2>> dp(k + 1, {0, INT_MIN / 2});
    for (int price : prices) {
        for (int j = k; j >= 1; --j) {
            dp[j][0] = max(dp[j][0], dp[j][1] + price);     // 賣出
            dp[j][1] = max(dp[j][1], dp[j - 1][0] - price); // 買入
        }
    }
    return dp[k][0];
}
```

**C++ 模板（含冷凍期，三狀態）**：

```cpp
// 狀態 0: 未持有（可以買入）
// 狀態 1: 持有股票
// 狀態 2: 冷凍期（剛賣出，下一天不能買）
int maxProfit(vector<int>& prices) {
    int n = prices.size();
    // f0: 未持有, f1: 持有, f2: 冷凍期
    int f0 = 0, f1 = INT_MIN / 2, f2 = 0;
    for (int p : prices) {
        int new_f_0 = max(f0, f2);     // 保持未持有，或從冷凍期恢復
        int new_f_1 = max(f1, f0 - p); // 保持持有，或從未持有買入
        int new_f_2 = f1 + p;          // 從持有賣出，進入冷凍期
        f0 = new_f_0;
        f1 = new_f_1;
        f2 = new_f_2;
    }
    return max(f0, f2);
}
```

**狀態機 DP 基礎**：每個位置有若干狀態可供轉移，根據前一個位置的狀態和當前的選擇決定新狀態。

**C++ 模板（粉刷房子 / 相鄰不同色）**：

```cpp
// costs[i][j] = 第 i 間房子塗第 j 種顏色的成本
// 相鄰房子不能塗同色，求最小總成本
int minCost(vector<vector<int>>& costs) {
    int n = costs.size(), k = costs[0].size();
    vector<int> dp = costs[0]; // dp[j] = 前 i 間房子，第 i 間塗色 j 的最小成本
    for (int i = 1; i < n; ++i) {
        vector<int> ndp(k, INT_MAX);
        for (int j = 0; j < k; ++j) { // 第 i 間塗色 j
            for (int p = 0; p < k; ++p) { // 第 i-1 間塗色 p
                if (p != j) { // 相鄰不同色
                    ndp[j] = min(ndp[j], dp[p] + costs[i][j]);
                }
            }
        }
        dp = ndp;
    }
    return *min_element(dp.begin(), dp.end());
}
```

一維 DP 是最基礎的線性 DP，狀態轉移發生在陣列的前綴/後綴之間，例如從 $f[i-1]$ 轉移到 $f[i]$，或者從 $f[j]$ 轉移到 $f[i]$。

**核心思想**：
- 定義 `f[i]` 表示考慮前 `i` 個元素的最優解
- 從前面的狀態 `f[j]` 轉移到當前狀態 `f[i]`
- 時間複雜度通常為 $O(n)$ 或 $O(n^2)$

**常見模式**：

1. **從前一個狀態轉移**：$f[i] = f[i-1] + ...$ （例如：爬樓梯）
2. **從任意前面狀態轉移**：$f[i] = \max_{j<i} (f[j] + ...)$ （例如：最長遞增子序列）
3. **帶條件的轉移**：只有滿足某個條件才能從 $f[j]$ 轉移到 $f[i]$

**C++ 模板**：

```cpp
// 一維 DP 基礎模板
int solve(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n);

    // 初始化
    dp[0] = nums[0];

    // 轉移
    for (int i = 1; i < n; i++) {
        dp[i] = dp[i - 1] + nums[i]; // 從前一個狀態轉移
    }

    return dp[n - 1];
}

// 從多個前面狀態轉移
int solveMulti(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n, INT_MIN);

    dp[0] = nums[0];

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (滿足條件) {
                dp[i] = max(dp[i], dp[j] + nums[i]);
            }
        }
    }

    return *max_element(dp.begin(), dp.end());
}

// 最長遞增子序列（LIS）
int lengthOfLis(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n, 1); // dp[i] = 以 nums[i] 結尾的 LIS 長度

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (nums[j] < nums[i]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    return *max_element(dp.begin(), dp.end());
}

// LIS 優化版（二分查找）- O(n log n)
int lengthOfLisOptimized(vector<int>& nums) {
    vector<int> tails; // tails[i] = 長度為 i+1 的 LIS 的最小尾部元素

    for (int num : nums) {
        auto it = lower_bound(tails.begin(), tails.end(), num);
        if (it == tails.end()) {
            tails.push_back(num);
        } else {
            *it = num;
        }
    }

    return tails.size();
}

// 最大子陣列和（Kadane's Algorithm）
int maxSubArray(vector<int>& nums) {
    int n = nums.size();
    int max_sum = nums[0];
    int current_sum = nums[0];

    for (int i = 1; i < n; i++) {
        current_sum = max(nums[i], current_sum + nums[i]);
        max_sum = max(max_sum, current_sum);
    }

    return max_sum;
}

// DP 版本的最大子陣列和
int maxSubArrayDp(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n); // dp[i] = 以 nums[i] 結尾的最大子陣列和

    dp[0] = nums[0];
    int max_sum = dp[0];

    for (int i = 1; i < n; i++) {
        dp[i] = max(nums[i], dp[i - 1] + nums[i]);
        max_sum = max(max_sum, dp[i]);
    }

    return max_sum;
}

// 打家劫舍
int rob(vector<int>& nums) {
    int n = nums.size();
    if (n == 0) {
        return 0;
    }
    if (n == 1) {
        return nums[0];
    }

    vector<int> dp(n);
    dp[0] = nums[0];
    dp[1] = max(nums[0], nums[1]);

    for (int i = 2; i < n; i++) {
        dp[i] = max(dp[i - 1], dp[i - 2] + nums[i]);
    }

    return dp[n - 1];
}

// 空間優化版（滾動變量）
int robOptimized(vector<int>& nums) {
    int prev2 = 0, prev1 = 0;

    for (int num : nums) {
        int current = max(prev1, prev2 + num);
        prev2 = prev1;
        prev1 = current;
    }

    return prev1;
}
```

不相交區間 DP 用於處理選擇若干個不相交的區間，使得某個指標最優的問題。

**核心思想**：
- 定義 f[i] 表示考慮前 i 個區間的最優解
- 對於每個區間，選或不選
- 如果選擇當前區間，需要找到與它不相交的最後一個區間

**常見問題**：
- 加權區間調度（Weighted Interval Scheduling）
- 最多不相交區間數
- 區間覆蓋問題

**C++ 模板**：

```cpp
// 加權區間調度：選擇不相交區間使得權重和最大
struct Interval {
    int start, end, weight;
    bool operator<(const Interval& other) const {
        return end < other.end; // 按結束時間排序
    }
};

int maxWeight(vector<Interval>& intervals) {
    int n = intervals.size();
    sort(intervals.begin(), intervals.end());

    vector<int> dp(n); // dp[i] = 考慮前 i+1 個區間的最大權重
    dp[0] = intervals[0].weight;

    for (int i = 1; i < n; i++) {
        // 不選當前區間
        int not_take = dp[i - 1];

        // 選當前區間：找最後一個不相交的區間
        int take = intervals[i].weight;
        int j = i - 1;
        while (j >= 0 && intervals[j].end > intervals[i].start) {
            j--;
        }
        if (j >= 0) {
            take += dp[j];
        }

        dp[i] = max(not_take, take);
    }

    return dp[n - 1];
}

// 優化：二分查找最後一個不相交區間
int findLastNonOverlapping(vector<Interval>& intervals, int i) {
    int left = 0, right = i - 1;
    int result = -1;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (intervals[mid].end <= intervals[i].start) {
            result = mid;
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    return result;
}

int maxWeightOptimized(vector<Interval>& intervals) {
    int n = intervals.size();
    sort(intervals.begin(), intervals.end());

    vector<int> dp(n);
    dp[0] = intervals[0].weight;

    for (int i = 1; i < n; i++) {
        int not_take = dp[i - 1];
        int take = intervals[i].weight;

        int j = findLastNonOverlapping(intervals, i);
        if (j != -1) {
            take += dp[j];
        }

        dp[i] = max(not_take, take);
    }

    return dp[n - 1];
}

// 最多不相交區間數（貪心 + DP）
int maxDisjointIntervals(vector<vector<int>>& intervals) {
    sort(intervals.begin(), intervals.end(), [](auto& a, auto& b) {
        return a[1] < b[1]; // 按結束時間排序
    });

    int count = 1;
    int end = intervals[0][1];

    for (int i = 1; i < intervals.size(); i++) {
        if (intervals[i][0] >= end) {
            count++;
            end = intervals[i][1];
        }
    }

    return count;
}

// 用 DP 實現
int maxDisjointIntervalsDp(vector<vector<int>>& intervals) {
    int n = intervals.size();
    sort(intervals.begin(), intervals.end(), [](auto& a, auto& b) {
        return a[1] < b[1];
    });

    vector<int> dp(n, 1); // dp[i] = 以第 i 個區間結尾的最多不相交區間數

    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (intervals[j][1] <= intervals[i][0]) {
                dp[i] = max(dp[i], dp[j] + 1);
            }
        }
    }

    return *max_element(dp.begin(), dp.end());
}

// 會議室 II：最少需要多少個會議室
int minMeetingRooms(vector<vector<int>>& intervals) {
    vector<int> start, end;

    for (auto& interval : intervals) {
        start.push_back(interval[0]);
        end.push_back(interval[1]);
    }

    sort(start.begin(), start.end());
    sort(end.begin(), end.end());

    int rooms = 0, max_rooms = 0;
    int i = 0, j = 0;

    while (i < start.size()) {
        if (start[i] < end[j]) {
            rooms++;
            max_rooms = max(max_rooms, rooms);
            i++;
        } else {
            rooms--;
            j++;
        }
    }

    return max_rooms;
}
```

子陣列 DP 處理連續子陣列的最優解問題，通常定義 $f[i]$ 表示以位置 $i$ 結尾的子陣列的最優值。

**核心思想**：
- `f[i]` 表示以 `nums[i]` 結尾的子陣列的某個屬性
- 從 `f[i - 1]` 轉移到 `f[i]`
- 通常需要維護前綴信息

**常見問題**：
- 最大/最小子陣列和
- 最長連續遞增子陣列
- 乘積最大子陣列

**C++ 模板**：

```cpp
// 最大子陣列和
int maxSubArray(vector<int>& nums) {
    int n = nums.size();
    int max_sum = nums[0];
    int current_sum = nums[0];

    for (int i = 1; i < n; i++) {
        current_sum = max(nums[i], current_sum + nums[i]);
        max_sum = max(max_sum, current_sum);
    }

    return max_sum;
}

// DP 陣列版本
int maxSubArrayDp(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp(n); // dp[i] = 以 nums[i] 結尾的最大子陣列和
    dp[0] = nums[0];
    int max_sum = dp[0];

    for (int i = 1; i < n; i++) {
        dp[i] = max(nums[i], dp[i - 1] + nums[i]);
        max_sum = max(max_sum, dp[i]);
    }

    return max_sum;
}

// 乘積最大子陣列
int maxProduct(vector<int>& nums) {
    int n = nums.size();
    int max_prod = nums[0];
    int currentMax = nums[0]; // 以當前位置結尾的最大乘積
    int currentMin = nums[0]; // 以當前位置結尾的最小乘積（負數可能變最大）

    for (int i = 1; i < n; i++) {
        if (nums[i] < 0) {
            swap(currentMax, currentMin); // 負數會使最大變最小，最小變最大
        }

        currentMax = max(nums[i], currentMax * nums[i]);
        currentMin = min(nums[i], currentMin * nums[i]);

        max_prod = max(max_prod, currentMax);
    }

    return max_prod;
}

// DP 陣列版本
int maxProductDp(vector<int>& nums) {
    int n = nums.size();
    vector<int> dp_max(n), dp_min(n);

    dp_max[0] = dp_min[0] = nums[0];
    int result = nums[0];

    for (int i = 1; i < n; i++) {
        dp_max[i] = max({nums[i], dp_max[i - 1] * nums[i], dp_min[i - 1] * nums[i]});
        dp_min[i] = min({nums[i], dp_max[i - 1] * nums[i], dp_min[i - 1] * nums[i]});
        result = max(result, dp_max[i]);
    }

    return result;
}

// 最長連續遞增子序列（子陣列）
int findLengthOfLcis(vector<int>& nums) {
    int n = nums.size();
    if (n == 0) {
        return 0;
    }

    int max_len = 1;
    int current_len = 1;

    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            current_len++;
            max_len = max(max_len, current_len);
        } else {
            current_len = 1;
        }
    }

    return max_len;
}

// 環形子陣列的最大和
int maxSubarraySumCircular(vector<int>& nums) {
    int n = nums.size();

    // 情況 1：最大子陣列不跨越邊界
    int max_kadane = kadane(nums);

    // 情況 2：最大子陣列跨越邊界 = 總和 - 最小子陣列
    int total_sum = 0;
    for (int i = 0; i < n; i++) {
        total_sum += nums[i];
        nums[i] = -nums[i]; // 取反
    }

    int min_kadane = kadane(nums);
    int maxWrap = total_sum + min_kadane; // 因為 min_kadane 是負的

    // 特殊情況：所有數都是負數
    if (maxWrap == 0) {
        return max_kadane;
    }

    return max(max_kadane, maxWrap);
}

int kadane(vector<int>& nums) {
    int max_sum = nums[0];
    int current_sum = nums[0];

    for (int i = 1; i < nums.size(); i++) {
        current_sum = max(nums[i], current_sum + nums[i]);
        max_sum = max(max_sum, current_sum);
    }

    return max_sum;
}

// K 次取反後最大化的陣列和
int largestSumAfterKNegations(vector<int>& nums, int k) {
    sort(nums.begin(), nums.end());
    int n = nums.size();

    // 盡量翻轉負數
    for (int i = 0; i < n && k > 0; i++) {
        if (nums[i] < 0) {
            nums[i] = -nums[i];
            k--;
        }
    }

    // 如果還有剩餘次數，翻轉最小的數
    if (k % 2 == 1) {
        sort(nums.begin(), nums.end());
        nums[0] = -nums[0];
    }

    return accumulate(nums.begin(), nums.end(), 0);
}
```

合法子序列 DP 計算滿足某種條件的子序列的最長長度、個數、元素和等。

**核心思想**：
- 定義 `f[x]` 表示以元素 `x` 結尾的合法子序列的屬性
- 注意 `x` 是元素值，不是下標
- 從子序列的倒數第二個元素轉移過來

**注意**：這裏的 $x$ 不是下標，是元素值。如果 $x$ 不是整數，或者值域範圍很大，可以用雜湊表代替陣列。
- 如果值域很大，使用雜湊表代替陣列

**常見問題**：
- 等差數列子序列
- 等比數列子序列
- 特定規則的子序列

**C++ 模板**：

```cpp
// 最長等差數列（值域較小時用陣列）
int longestArithSeqLength(vector<int>& nums) {
    int n = nums.size();
    int max_len = 2;

    // dp[i][diff] = 以 nums[i] 結尾、公差為 diff 的最長等差數列長度
    vector<unordered_map<int, int>> dp(n);

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < i; j++) {
            int diff = nums[i] - nums[j];
            dp[i][diff] = dp[j].count(diff) ? dp[j][diff] + 1 : 2;
            max_len = max(max_len, dp[i][diff]);
        }
    }

    return max_len;
}

// 等差數列劃分 II：子序列
long long numberOfArithmeticSlices(vector<int>& nums) {
    int n = nums.size();
    long long count = 0;

    // dp[i][diff] = 以 nums[i] 結尾、公差為 diff 的等差子序列個數
    vector<unordered_map<long long, int>> dp(n);

    for (int i = 0; i < n; i++) {
        for (int j = 0; j < i; j++) {
            long long diff = (long long)nums[i] - nums[j];
            int prev = dp[j].count(diff) ? dp[j][diff] : 0;
            dp[i][diff] += prev + 1;
            count += prev; // 只計算長度 >= 3 的
        }
    }

    return count;
}

// 刪除一個元素使陣列嚴格遞增
bool canBeIncreasing(vector<int>& nums) {
    int n = nums.size();
    int removed = 0;

    for (int i = 1; i < n; i++) {
        if (nums[i] <= nums[i - 1]) {
            removed++;
            if (removed > 1) {
                return false;
            }

            // 刪除 nums[i] 或 nums[i-1]
            if (i > 1 && nums[i] <= nums[i - 2]) {
                nums[i] = nums[i - 1]; // 相當於刪除 nums[i-1]
            }
        }
    }

    return true;
}

// 擺動序列
int wiggleMaxLength(vector<int>& nums) {
    int n = nums.size();
    if (n < 2) {
        return n;
    }

    // up[i] = 以 nums[i] 結尾且最後是上升的擺動序列最大長度
    // down[i] = 以 nums[i] 結尾且最後是下降的擺動序列最大長度
    int up = 1, down = 1;

    for (int i = 1; i < n; i++) {
        if (nums[i] > nums[i - 1]) {
            up = down + 1; // 從下降轉為上升
        } else if (nums[i] < nums[i - 1]) {
            down = up + 1; // 從上升轉為下降
        }
    }

    return max(up, down);
}

// 使用雜湊表的示例：最長斐波那契子序列
int lenLongestFibSubseq(vector<int>& arr) {
    int n = arr.size();
    unordered_set<int> s(arr.begin(), arr.end());
    int max_len = 0;

    for (int i = 0; i < n; i++) {
        for (int j = i + 1; j < n; j++) {
            int a = arr[i], b = arr[j];
            int len = 2;

            while (s.count(a + b)) {
                int temp = b;
                b = a + b;
                a = temp;
                len++;
            }

            max_len = max(max_len, len);
        }
    }

    return max_len >= 3 ? max_len : 0;
}

// DP 優化版本
int lenLongestFibSubseqDp(vector<int>& arr) {
    int n = arr.size();
    unordered_map<int, int> index;
    for (int i = 0; i < n; i++) {
        index[arr[i]] = i;
    }

    // dp[i][j] = 以 arr[i], arr[j] 結尾的斐波那契序列長度
    vector<vector<int>> dp(n, vector<int>(n, 2));
    int max_len = 0;

    for (int j = 0; j < n; j++) {
        for (int i = 0; i < j; i++) {
            int prev = arr[j] - arr[i];
            if (prev < arr[i] && index.count(prev)) {
                int k = index[prev];
                dp[i][j] = dp[k][i] + 1;
            }
            max_len = max(max_len, dp[i][j]);
        }
    }

    return max_len >= 3 ? max_len : 0;
}
```

子矩形 DP 處理二維矩陣中的矩形區域問題，通常結合前綴和或壓縮維度技巧。

**核心思想**：
- 將二維問題壓縮為一維問題
- 枚舉矩形的上下邊界，將問題轉化為一維陣列
- 使用前綴和、雜湊表等輔助結構

**常見問題**：
- 最大矩形和
- 子矩形和為 K 的個數
- 最大正方形

**C++ 模板**：

```cpp
// 最大矩形和
int maxSumSubmatrix(vector<vector<int>>& matrix) {
    int m = matrix.size(), n = matrix[0].size();
    int max_sum = INT_MIN;

    // 枚舉上邊界
    for (int top = 0; top < m; top++) {
        vector<int> col_sum(n, 0); // 壓縮後的一維陣列

        // 枚舉下邊界
        for (int bottom = top; bottom < m; bottom++) {
            // 累加當前行到 col_sum
            for (int col = 0; col < n; col++) {
                col_sum[col] += matrix[bottom][col];
            }

            // 在一維陣列上求最大子陣列和
            int current_sum = 0;
            for (int val : col_sum) {
                current_sum = max(val, current_sum + val);
                max_sum = max(max_sum, current_sum);
            }
        }
    }

    return max_sum;
}

// 和不超過 K 的最大矩形和
int maxSumSubmatrix(vector<vector<int>>& matrix, int k) {
    int m = matrix.size(), n = matrix[0].size();
    int result = INT_MIN;

    for (int top = 0; top < m; top++) {
        vector<int> col_sum(n, 0);

        for (int bottom = top; bottom < m; bottom++) {
            for (int col = 0; col < n; col++) {
                col_sum[col] += matrix[bottom][col];
            }

            // 找不超過 k 的最大子陣列和
            set<int> prefix_sums;
            prefix_sums.insert(0);
            int sum = 0;

            for (int val : col_sum) {
                sum += val;
                // 找最小的 prefix >= sum - k
                auto it = prefix_sums.lower_bound(sum - k);
                if (it != prefix_sums.end()) {
                    result = max(result, sum - *it);
                }
                prefix_sums.insert(sum);
            }
        }
    }

    return result;
}

// 最大正方形
int maximalSquare(vector<vector<char>>& matrix) {
    int m = matrix.size(), n = matrix[0].size();
    vector<vector<int>> dp(m, vector<int>(n, 0));
    int max_side = 0;

    // dp[i][j] = 以 (i,j) 為右下角的最大正方形邊長
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (matrix[i][j] == '1') {
                if (i == 0 || j == 0) {
                    dp[i][j] = 1;
                } else {
                    dp[i][j] = min({dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]}) + 1;
                }
                max_side = max(max_side, dp[i][j]);
            }
        }
    }

    return max_side * max_side;
}

// 最大矩形（柱狀圖法）
int maximalRectangle(vector<vector<char>>& matrix) {
    if (matrix.empty()) {
        return 0;
    }

    int m = matrix.size(), n = matrix[0].size();
    vector<int> heights(n, 0);
    int max_area = 0;

    for (int i = 0; i < m; i++) {
        // 更新高度陣列
        for (int j = 0; j < n; j++) {
            heights[j] = (matrix[i][j] == '1') ? heights[j] + 1 : 0;
        }

        // 計算當前柱狀圖的最大矩形
        max_area = max(max_area, largestRectangleArea(heights));
    }

    return max_area;
}

// 柱狀圖中最大矩形
int largestRectangleArea(vector<int>& heights) {
    int n = heights.size();
    stack<int> stk;
    int max_area = 0;

    for (int i = 0; i <= n; i++) {
        int h = (i == n) ? 0 : heights[i];

        while (!stk.empty() && h < heights[stk.top()]) {
            int height = heights[stk.top()];
            stk.pop();
            int width = stk.empty() ? i : (i - stk.top() - 1);
            max_area = max(max_area, height * width);
        }

        stk.push(i);
    }

    return max_area;
}

// 統計全 1 子矩形
int numSubmat(vector<vector<int>>& mat) {
    int m = mat.size(), n = mat[0].size();
    vector<vector<int>> heights(m, vector<int>(n, 0));
    int count = 0;

    // 計算每個位置向上的連續 1 的高度
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (mat[i][j] == 1) {
                heights[i][j] = (i == 0) ? 1 : heights[i - 1][j] + 1;
            }
        }
    }

    // 對每一行，計算以該行為底的矩形數
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            int min_height = heights[i][j];
            for (int k = j; k >= 0 && heights[i][k] > 0; k--) {
                min_height = min(min_height, heights[i][k]);
                count += min_height;
            }
        }
    }

    return count;
}
```

多維 DP 涉及多個維度的狀態，需要仔細設計狀態表示和轉移方程。

**核心思想**：
- 定義多維狀態 f[i][j][k][...] 表示多個維度的組合
- 狀態數 = 每個維度的大小的乘積
- 時間複雜度通常較高，需要優化

**常見問題**：
- 編輯距離（二維）
- 多條件限制的 DP
- 多個序列的匹配

**C++ 模板**：

```cpp
// 編輯距離（二維 DP）
int minDistance(string word_1, string word_2) {
    int m = word_1.size(), n = word_2.size();
    vector<vector<int>> dp(m + 1, vector<int>(n + 1));

    // 初始化
    for (int i = 0; i <= m; i++) {
        dp[i][0] = i; // 刪除所有字符
    }
    for (int j = 0; j <= n; j++) {
        dp[0][j] = j; // 插入所有字符
    }

    // 轉移
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (word_1[i - 1] == word_2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1]; // 不需要操作
            } else {
                dp[i][j] = min({
                    dp[i - 1][j] + 1,     // 刪除
                    dp[i][j - 1] + 1,     // 插入
                    dp[i - 1][j - 1] + 1  // 替換
                });
            }
        }
    }

    return dp[m][n];
}

// 最長公共子序列（二維 DP）
int longestCommonSubsequence(string text_1, string text_2) {
    int m = text_1.size(), n = text_2.size();
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));

    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (text_1[i - 1] == text_2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
    }

    return dp[m][n];
}

// 不同的子序列（二維 DP）
int numDistinct(string s, string t) {
    int m = s.size(), n = t.size();
    vector<vector<long long>> dp(m + 1, vector<long long>(n + 1, 0));

    // 空串是任何串的子序列
    for (int i = 0; i <= m; i++) {
        dp[i][0] = 1;
    }

    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            dp[i][j] = dp[i - 1][j]; // 不使用 s[i-1]
            if (s[i - 1] == t[j - 1]) {
                dp[i][j] += dp[i - 1][j - 1]; // 使用 s[i-1]
            }
        }
    }

    return dp[m][n];
}

// 三維 DP：交錯字串
bool isInterleave(string s_1, string s_2, string s_3) {
    int m = s_1.size(), n = s_2.size();
    if (m + n != s_3.size()) {
        return false;
    }

    vector<vector<bool>> dp(m + 1, vector<bool>(n + 1, false));
    dp[0][0] = true;

    // 只使用 s_1
    for (int i = 1; i <= m; i++) {
        dp[i][0] = dp[i - 1][0] && (s_1[i - 1] == s_3[i - 1]);
    }

    // 只使用 s_2
    for (int j = 1; j <= n; j++) {
        dp[0][j] = dp[0][j - 1] && (s_2[j - 1] == s_3[j - 1]);
    }

    // 同時使用 s_1 和 s_2
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            bool match1 = (s_1[i - 1] == s_3[i + j - 1]) && dp[i - 1][j];
            bool match2 = (s_2[j - 1] == s_3[i + j - 1]) && dp[i][j - 1];
            dp[i][j] = match1 || match2;
        }
    }

    return dp[m][n];
}

// 四維 DP：兩個字串的最小 ASCII 刪除和
int minimumDeleteSum(string s_1, string s_2) {
    int m = s_1.size(), n = s_2.size();
    vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));

    // 刪除 s_1 的所有字符
    for (int i = 1; i <= m; i++) {
        dp[i][0] = dp[i - 1][0] + s_1[i - 1];
    }

    // 刪除 s_2 的所有字符
    for (int j = 1; j <= n; j++) {
        dp[0][j] = dp[0][j - 1] + s_2[j - 1];
    }

    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (s_1[i - 1] == s_2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1];
            } else {
                dp[i][j] = min(
                    dp[i - 1][j] + s_1[i - 1], // 刪除 s_1[i-1]
                    dp[i][j - 1] + s_2[j - 1]  // 刪除 s_2[j-1]
                );
            }
        }
    }

    return dp[m][n];
}

// 空間優化：滾動陣列
int minDistanceOptimized(string word_1, string word_2) {
    int m = word_1.size(), n = word_2.size();
    vector<int> prev(n + 1), curr(n + 1);

    for (int j = 0; j <= n; j++) {
        prev[j] = j;
    }

    for (int i = 1; i <= m; i++) {
        curr[0] = i;
        for (int j = 1; j <= n; j++) {
            if (word_1[i - 1] == word_2[j - 1]) {
                curr[j] = prev[j - 1];
            } else {
                curr[j] = min({prev[j], curr[j - 1], prev[j - 1]}) + 1;
            }
        }
        swap(prev, curr);
    }

    return prev[n];
}
```

計數 DP 用於計算滿足某種條件的方案數，通常涉及組合數學。

**核心思想**：
- $f[i]$ 表示到達狀態 $i$ 的方案數
- 方案數相加：$f[i] = f[j_1] + f[j_2] + \cdots$
- 注意取模運算和大數處理

**常見問題**：
- 路徑計數
- 組合方案數
- 數位 DP

**C++ 模板**：

```cpp
// 不同路徑
int uniquePaths(int m, int n) {
    vector<vector<int>> dp(m, vector<int>(n, 1));

    for (int i = 1; i < m; i++) {
        for (int j = 1; j < n; j++) {
            dp[i][j] = dp[i - 1][j] + dp[i][j - 1];
        }
    }

    return dp[m - 1][n - 1];
}

// 空間優化版本
int uniquePathsOptimized(int m, int n) {
    vector<int> dp(n, 1);

    for (int i = 1; i < m; i++) {
        for (int j = 1; j < n; j++) {
            dp[j] += dp[j - 1];
        }
    }

    return dp[n - 1];
}

// 不同路徑 II（有障礙物）
int uniquePathsWithObstacles(vector<vector<int>>& grid) {
    int m = grid.size(), n = grid[0].size();
    if (grid[0][0] == 1) {
        return 0;
    }

    vector<vector<int>> dp(m, vector<int>(n, 0));
    dp[0][0] = 1;

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == 1) {
                dp[i][j] = 0;
            } else if (i > 0 || j > 0) {
                int from_up = (i > 0) ? dp[i - 1][j] : 0;
                int from_left = (j > 0) ? dp[i][j - 1] : 0;
                dp[i][j] = from_up + from_left;
            }
        }
    }

    return dp[m - 1][n - 1];
}

// 爬樓梯（方案數）
int climbStairs(int n) {
    if (n <= 2) {
        return n;
    }

    int prev2 = 1, prev1 = 2;

    for (int i = 3; i <= n; i++) {
        int curr = prev1 + prev2;
        prev2 = prev1;
        prev1 = curr;
    }

    return prev1;
}

// 解碼方法（帶模運算）
int numDecodings(string s) {
    int n = s.size();
    const int kMod = 1e9 + 7;

    if (s[0] == '0') {
        return 0;
    }

    vector<long long> dp(n + 1, 0);
    dp[0] = 1;
    dp[1] = 1;

    for (int i = 2; i <= n; i++) {
        // 單個數字解碼
        if (s[i - 1] != '0') {
            dp[i] = dp[i - 1];
        }

        // 兩個數字解碼
        int two_digit = (s[i - 2] - '0') * 10 + (s[i - 1] - '0');
        if (two_digit >= 10 && two_digit <= 26) {
            dp[i] = (dp[i] + dp[i - 2]) % kMod;
        }
    }

    return dp[n];
}

// 目標和（方案數）
int findTargetSumWays(vector<int>& nums, int target) {
    int sum = accumulate(nums.begin(), nums.end(), 0);

    // sum - 2*neg = target => neg = (sum - target) / 2
    if ((sum - target) % 2 != 0 || sum < target) {
        return 0;
    }

    int neg = (sum - target) / 2;
    vector<int> dp(neg + 1, 0);
    dp[0] = 1;

    for (int num : nums) {
        for (int j = neg; j >= num; j--) {
            dp[j] += dp[j - num];
        }
    }

    return dp[neg];
}

// 組合總和 IV（方案數）
int combinationSum4(vector<int>& nums, int target) {
    vector<unsigned int> dp(target + 1, 0);
    dp[0] = 1;

    for (int i = 1; i <= target; i++) {
        for (int num : nums) {
            if (i >= num) {
                dp[i] += dp[i - num];
            }
        }
    }

    return dp[target];
}

// 整數拆分（最大乘積）
int integerBreak(int n) {
    if (n <= 3) {
        return n - 1;
    }

    vector<int> dp(n + 1, 0);
    dp[1] = 1;
    dp[2] = 2;
    dp[3] = 3;

    for (int i = 4; i <= n; i++) {
        for (int j = 1; j <= i / 2; j++) {
            dp[i] = max(dp[i], dp[j] * dp[i - j]);
        }
    }

    return dp[n];
}

// 貪心優化
int integerBreakGreedy(int n) {
    if (n == 2) return 1;
    if (n == 3) return 2;

    int product = 1;
    while (n > 4) {
        product *= 3;
        n -= 3;
    }
    return product * n;
}
```

