講解：[區間 DP【基礎算法精講 22】](https://www.bilibili.com/video/BV1Gs4y1E7EU/)

從陣列的左右兩端不斷縮短，求解關於某段下標區間的最優值。

一般定義 f[i][j] 表示下標區間 [i,j] 的最優值。

---



**區間 DP：最長迴文子序列**：
- `dp[i][j]` 表示 `s[i..j]` 中最長迴文子序列的長度
- 若 `s[i] == s[j]`：`dp[i][j] = dp[i+1][j-1] + 2`
- 否則：`dp[i][j] = max(dp[i+1][j], dp[i][j-1])`

```cpp
// 區間 DP：dp[i][j] = s[i..j] 的最長迴文子序列長度
int longestPalindromeSubseq(string& s) {
    int n = s.size();
    vector<vector<int>> dp(n, vector<int>(n, 0));
    for (int i = n - 1; i >= 0; --i) {
        dp[i][i] = 1;
        for (int j = i + 1; j < n; ++j) {
            if (s[i] == s[j]) {
                dp[i][j] = dp[i + 1][j - 1] + 2; // 首尾相同，各貢獻 1
            } else {
                dp[i][j] = max(dp[i + 1][j], dp[i][j - 1]); // 首尾不同，取較優
            }
        }
    }
    return dp[0][n - 1];
}
```

子集和 DP（Sum Over Subsets DP，SOS DP），國內演算法競賽圈一般叫高維字首和。

[原理講解（方法二）](https://leetcode.cn/problems/maximum-product-of-two-integers-with-no-common-bits/solutions/3768219/mo-ban-gao-wei-qian-zhui-he-sos-dppython-78fz/)

**模板（從子集轉移過來）**：

```cpp
// 高維字首和：f[S] = S 的所有子集中 a 的計數之和
// 時間複雜度 O(n + U log U)，其中 U = max(a)
vector<int> sosDp(const vector<int>& a) {
    if (a.empty()) {
        return {};
    }
    int mx = *max_element(a.begin(), a.end());
    int w = mx == 0 ? 1 : 32 - __builtin_clz(mx); // 位元寬度
    int u = 1 << w;                               // 全集大小
    vector<int> f(u, 0);
    for (int x : a) {
        f[x]++; // 初始化：每個值的出現次數
    }
    // 逐位合併：第 i 輪讓每個 S 吸收「第 i 位為 0」的子集
    for (int i = 0; i < w; ++i) {
        for (int s = 0; s < u; ++s) {
            // 第 i 位為 1
            if (s & (1 << i)) {
                f[s] += f[s ^ (1 << i)]; // 加上第 i 位為 0 的子集
            }
        }
    }
    return f; // f[S] = 所有 T⊆S 的 a 計數之和
}
```

**模板（從超集轉移過來）**：

```cpp
// 高維字尾和：f[S] = S 的所有超集中 a 的計數之和
vector<int> sosDpSuperset(const vector<int>& a) {
    if (a.empty()) {
        return {};
    }
    int mx = *max_element(a.begin(), a.end());
    int w = mx == 0 ? 1 : 32 - __builtin_clz(mx);
    int u = 1 << w;
    vector<int> f(u, 0);
    for (int x : a) {
        f[x]++;
    }
    // 逐位合併：第 i 輪讓每個 S 吸收「第 i 位為 1」的超集
    for (int i = 0; i < w; ++i) {
        for (int s = u - 1; s >= 0; --s) {
            // 第 i 位為 0
            if (!(s & (1 << i))) {
                f[s] += f[s | (1 << i)]; // 加上第 i 位為 1 的超集
            }
        }
    }
    return f; // f[S] = 所有 T⊇S 的 a 計數之和
}
```

暴力做法是列舉所有排列，時間複雜度 $O(n!)$，可解決 $n \leq 10$。

狀壓 DP 優化至 $O(n \cdot 2^n)$，可解決 $n \leq 20$。

一般有兩種定義方式：
1. $f[S]$ 表示已經排列好的元素集合為 $S$ 時的最優值。
2. $f[S]$ 表示可以選的元素集合為 $S$ 時的最優值。

> 注：部分題目由於暴搜+剪枝也能過，難度分僅供參考。

```cpp
// 排列型狀壓 DP（相鄰無關）
// f[S] = 已選集合為 S 時的最優值
vector<int> f(1 << n, 0);
for (int s = 0; s < (1 << n); ++s) {
    int pos = __builtin_popcount(s); // s 中 1 的個數 = 當前要填的位置
    for (int i = 0; i < n; ++i) {
        if (s & (1 << i)) {
            continue; // i 已選
        }
        f[s | (1 << i)] = max(f[s | (1 << i)], f[s] + cost(pos, i));
    }
}
```

[數位 DP v1.0 模板講解](https://www.bilibili.com/video/BV1rS4y1s721/?t=19m36s)

[數位 DP v2.0 模板講解](https://www.bilibili.com/video/BV1Fg4y1Q7wv/?t=31m28s)（上下界數位 DP）

下面是數位 DP v2.1 模板。相比 v2.0，不需要寫 isNum 引數。

> 注：只有上界約束的題目，相當於 `low = 0` 或者 `low = 1`。

**C++ 模板（統計 [low, high] 中恰好包含 target 個 0 的數字個數）**：

```cpp
// 數位 DP：統計 [low, high] 中滿足條件的數字個數
long long digitDp(long long low, long long high, int target) {
    string low_s = to_string(low);
    string high_s = to_string(high);
    int n = high_s.length();          // 以 high 的位數為基準
    int diff_lh = n - low_s.length(); // low 和 high 的位數差

    // memo[位置][已有的0個數][是否貼下界][是否貼上界]
    vector memo(n, vector(target + 1, vector(2, vector<long long>(2, -1))));

    // i: 當前填第幾位（從高位到低位，0-indexed）
    // cnt0: 目前已經填了多少個 0
    // limit_low: 前面的位是否都貼著 low 的下界
    // limit_high: 前面的位是否都貼著 high 的上界
    function<long long(int, int, bool, bool)> dfs = [&](int i, int cnt0, bool limit_low,
                                                        bool limit_high) -> long long {
        if (cnt0 > target) {
            return 0; // 剪枝：0 的個數已超過目標
        }
        if (i == n) {
            return cnt0 == target ? 1 : 0; // 所有位都填完，檢查是否恰好
        }
        if (memo[i][cnt0][limit_low][limit_high] != -1) {
            return memo[i][cnt0][limit_low][limit_high]; // 已計算過
        }

        // 確定當前位可以填的數字範圍 [lo, hi]
        // 若貼下界且當前位在 low 的範圍內，最小值為 low 對應位的數字
        int lo = (limit_low && i >= diff_lh) ? low_s[i - diff_lh] - '0' : 0;
        // 若貼上界，最大值為 high 對應位的數字；否則可以填 9
        int hi = limit_high ? high_s[i] - '0' : 9;
        long long res = 0;
        int start = lo;

        // 特殊處理：當前位在 low 的高位之前（即 high 比 low 多出來的高位）
        // 這些高位可以填 0（代表實際數字位數較少）
        if (limit_low && i < diff_lh) {
            // 填 0：相當於這個高位不存在（數字位數 < high 的位數）
            res = dfs(i + 1, 0, true, false);
            start = 1; // 非零數字從 1 開始
        }

        // 列舉當前位填的數字 d
        for (int d = start; d <= hi; ++d) {
            res += dfs(i + 1,
                       cnt0 + (d == 0 ? 1 : 0), // 更新 0 的計數
                       limit_low && (d == lo),  // 仍然貼著下界？
                       limit_high && (d == hi)  // 仍然貼著上界？
            );
        }
        return memo[i][cnt0][limit_low][limit_high] = res;
    };
    return dfs(0, 0, true, true); // 初始：貼著上下界
}
```

每個元素 `x` 都有一個相應的價值 `f(x)`，計算 `[low, high]` 中滿足題目約束的元素的價值總和。

例如 `f(x) = x` 是計算滿足題目約束的元素和，`f(x) = digsum(x)` 是計算滿足題目約束的元素的數位和。

**關鍵技巧**：回傳值改為 `$\{\text{cnt}, \text{sum}\}$`（個數和價值和）。每一位的貢獻為 $d \times$ 後續子問題的個數。

**C++ 模板（數位和，約束不同數字個數 $\leq k$）**：

```cpp
// 數位 DP（貢獻法）：統計合法數字的價值總和
long long digitDpContribution(long long low, long long high, int k) {
    string low_s = to_string(low);
    string high_s = to_string(high);
    int n = high_s.length();
    int diff_lh = n - low_s.length();

    // 回傳 {滿足條件的個數, 數位和的總和}
    struct Node {
        long long cnt, sum;
    };
    // memo[位置][已出現數字的 bitmask][貼下界][貼上界]
    // mask 用 10 位 bitmask 記錄出現過哪些數字（0~9）
    vector memo(n, vector(1024, vector(2, vector<Node>(2, {-1, -1}))));

    function<Node(int, int, bool, bool)> dfs = [&](int i, int mask, bool limit_low,
                                                   bool limit_high) -> Node {
        if (i == n) {
            return {1LL, 0LL}; // 構造完成，貢獻 1 個數，數位和由上層累加
        }
        if (memo[i][mask][limit_low][limit_high].cnt != -1) {
            return memo[i][mask][limit_low][limit_high];
        }

        int lo = (limit_low && i >= diff_lh) ? low_s[i - diff_lh] - '0' : 0;
        int hi = limit_high ? high_s[i] - '0' : 9;
        long long cnt = 0, sum = 0;
        int start = lo;

        if (limit_low && i < diff_lh) {
            auto res = dfs(i + 1, 0, true, false);
            cnt += res.cnt;
            sum += res.sum;
            start = 1;
        }

        for (int d = start; d <= hi; ++d) {
            // 更新 mask：前導零不記入（mask==0 且 d==0 時保持 0）
            int new_mask = (mask == 0 && d == 0) ? 0 : (mask | (1 << d));
            if (__builtin_popcount(new_mask) > k) {
                continue; // 不同數字個數超過 k，剪枝
            }
            auto res = dfs(i + 1, new_mask, limit_low && (d == lo), limit_high && (d == hi));
            cnt += res.cnt;
            // 當前位填 d，對每個合法數字貢獻 d（乘以後續的個數）
            sum += res.sum + (long long)d * res.cnt;
        }
        return memo[i][mask][limit_low][limit_high] = {cnt, sum};
    };
    return dfs(0, 0, true, true).sum;
}
```

**數位 DP（Digit DP）**：用於計算在某個數值範圍 `[low, high]` 內，滿足特定數位性質的整數個數（或價值總和）。

**核心思路**：逐位構造數字，用記憶化搜尋避免重複計算。每一位需要追蹤：
- **是否貼著上界/下界**（`limit_high` / `limit_low`）：決定當前位能填的數字範圍
- **題目相關的狀態**：如已出現的數字集合、數位和、餘數等

**通用框架**：
1. 將 low 和 high 轉成字串
2. 從高位到低位遞迴，每位嘗試填入合法數字
3. 用 `memo` 陣列記憶化

**常見變形**：
- 統計個數（10.1）：回傳滿足條件的數字個數
- 統計價值和（10.2）：回傳 {個數, 價值和}，用個數輔助計算貢獻
- 構造型（10.3）：找出滿足條件的具體數字（如迴文數）

```cpp
// 數位 DP 模板
int digitDp(const string& s) {
    int n = s.size();
    vector<vector<int>> memo(n, vector<int>(state_size, -1));

    // pos: 當前位置, state: 題目相關狀態, tight: 是否貼著上界, started: 是否已開始填數
    function<int(int, int, bool, bool)> dfs = [&](int pos, int state, bool tight,
                                                  bool started) -> int {
        // 到達末尾，若已開始則計入答案
        if (pos == n) {
            return started ? 1 : 0;
        }
        // 記憶化剪枝（非貼界且已開始才能記憶化）
        if (!tight && started && memo[pos][state] != -1) {
            return memo[pos][state];
        }

        int up = tight ? s[pos] - '0' : 9; // 當前位可填的最大值
        int res = 0;
        // 枚舉當前位可填的數字
        for (int d = 0; d <= up; d++) {
            res += dfs(pos + 1, new_state(state, d), tight && d == up, started || d > 0);
        }

        // 記憶化
        if (!tight && started) {
            memo[pos][state] = res;
        }
        return res;
    };
    return dfs(0, 0, true, false);
}
```

**注**：可能有同學覺得樹形 DP 沒有重複訪問同一個狀態（重疊子問題），並不能算作 DP，而是算作普通的遞迴。這麼說也有一定道理，不過考慮到思維方式和 DP 是一樣的自底向上，所以仍然叫做樹形 DP。此外，如果是自頂向下的遞迴做法，是存在重疊子問題的，一般要結合記憶化搜索實現。

